conn = sqlite3.connect(db_path)
cursor = conn.cursor()

# Insert the words safely
for term in terms_to_add:
    try:
        cursor.execute('''
            INSERT INTO terms (term, definition, root, language)
            VALUES (?, ?, ?, ?)
        ''', term)
    except sqlite3.IntegrityError:
        # Ignore if term already exists
        pass

conn.commit()
conn.close()

print(f"Added {len(terms_to_add)} terms to the Coptic Lexicon.")
